mapper.select:
SELECT * FROM ( SELECT count(*) over() as totalRow,M.*,N.LAST_CONTRACT_DATE,N.EVALUATION FROM (SELECT DISTINCT '表示' AS DISPLAY, A.CUSTOMER_ID ,A.BUTEN_CODE ,A.ACCOUNT_NUMBER AS ACCOUNT_NUMBER ,A.BROKER_CODE ,B.BROKER_NAME ,A.INTERMEDIARY_EMP_CD ,A.CUSTOMER_ATTRIBUTE ,A.CUSTOMER_ATTRIBUTE_NAME ,E.BROKER_CHARGE_NAME ,A.CORPORATION_KBN ,A.NAME_KANJI ,A.NAME_KANA ,CASE WHEN A.ZIP_CODE IS NULL THEN A.ADDRESS_KANJI1 ELSE SUBSTR(A.ZIP_CODE, 1, 3)||'-'||SUBSTR(A.ZIP_CODE, 4, 7)||' '||A.ADDRESS_KANJI1 END AS ADDRESS_KANJI1 ,A.ADDRESS_KANA1 ,A.PHONE_NUMBER ,A.PHONE_FLG ,A.SEX_KBN ,A.BIRTH_DAY ,A.AGE ,A.OPEN_ACCT_DATE ,A.TC_COMP_RANK ,MCI.BROKER_BRANCH_CODE ,MB.BRANCH_NAME
FROM ( SELECT * FROM MEDIATE_USER_ATTRIBUTE_INFO WHERE 1=1
AND BUTEN_CODE = #{butenCode}
AND ACCOUNT_NUMBER = TO_NUMBER(#{accountNumber})
AND BROKER_CODE NOT IN
#{brokerCodeExclude}
AND BROKER_CODE IN
#{brokerCodeExclude}
AND BROKER_CODE = #{brokerCode}
AND INTERMEDIARY_EMP_CD = #{intermediaryEmpCd}
AND CUSTOMER_ATTRIBUTE = #{customerAttribute}
AND PHONE_NUMBER = #{phoneNumber}
AND ( NAME_KANJI LIKE #{customerName} ESCAPE '!' OR NAME_KANA LIKE #{customerName} ESCAPE '!' )
AND ( NAME_KANJI = #{customerName} OR NAME_KANA = #{customerName} )
AND ADDRESS_KANJI1 LIKE #{address}
AND ADDRESS_KANJI1 = #{address}
AND TC_COMP_RANK >= #{tcCompRankFrom}
AND TC_COMP_RANK <= #{tcCompRankTo}
AND OPEN_ACCT_DATE >= #{accountOpenDate}
AND OPEN_ACCT_DATE <= #{accountCloseDate}
) A LEFT OUTER JOIN MEDIATE_CHARGE_INFO MCI ON MCI.BROKER_CODE = A.BROKER_CODE AND MCI.BROKER_CHARGE_CODE = A.INTERMEDIARY_EMP_CD AND ( SELECT COUNT(*) FROM MEDIATE_CHARGE_INFO MCI2 WHERE A.BROKER_CODE = MCI2.BROKER_CODE AND A.INTERMEDIARY_EMP_CD = MCI2.BROKER_CHARGE_CODE ) = 1 LEFT OUTER JOIN MEDIATE_BRANCH MB ON MB.BROKER_CODE = A.BROKER_CODE AND MCI.BROKER_BRANCH_CODE = MB.BROKER_BRANCH_CODE LEFT OUTER JOIN ( SELECT BROKER_CODE,BRANCH_NAME AS BROKER_NAME FROM MEDIATE_BRANCH WHERE BROKER_BRANCH_KIND='00' ) B ON B.BROKER_CODE = A.BROKER_CODE
LEFT OUTER JOIN ( SELECT DISTINCT BROKER_CODE,BROKER_CHARGE_CODE,BROKER_CHARGE_NAME FROM MEDIATE_CHARGE_INFO WHERE BROKER_CHARGE_CODE <>'0000' AND DELETE_FLG = '0' ) E ON E.BROKER_CODE = A.BROKER_CODE AND E.BROKER_CHARGE_CODE = A.INTERMEDIARY_EMP_CD )M LEFT OUTER JOIN (SELECT CUSTOMER_ID, BUTEN_CODE,ACCOUNT_NUMBER,LAST_CONTRACT_DATE,(PROF_LOSS_STOCK+PROF_LOSS_FOR_STOCK+PROF_LOSS_TRUST+PROF_LOSS_FOR_TRUST+PROF_LOSS_TRUST_STOCK) AS EVALUATION FROM USER_ATTRIBUTE ) N ON M.CUSTOMER_ID = N.CUSTOMER_ID
LEFT OUTER JOIN (SELECT MAX(CUSTOMER_ID) AS CUSTOMER_ID,SUM(ASSETS) AS ASSETS FROM USER_INFO_ASSETS GROUP BY CUSTOMER_ID) Q ON M.CUSTOMER_ID=Q.CUSTOMER_ID
WHERE 1 = 1
AND M.BROKER_BRANCH_CODE = #{branchCode}
AND TO_CHAR(N.LAST_CONTRACT_DATE,'YYYYMMDD') >= #{lastContractDateFrom}
AND TO_CHAR(N.LAST_CONTRACT_DATE,'YYYYMMDD') <= #{lastContractDateTo}
AND Q.ASSETS >= #{valuationFrom}
AND Q.ASSETS <= #{valuationTo}
AND P.COMMISSION >= #{comissionValueLimiterFrom}
AND P.COMMISSION <= #{comissionValueLimiterTo}
AND AGE >= #{ageMinimum, jdbcType=INTEGER}
AND AGE <= #{ageMaximum, jdbcType=INTEGER}
ORDER BY M.BROKER_CODE ASC,M.BUTEN_CODE ASC,M.ACCOUNT_NUMBER ASC
ORDER BY M.BUTEN_CODE ASC,M.ACCOUNT_NUMBER ASC
) WHERE 1 = 1
AND ROWNUM <= #{querySizeLimit}
